impl Solution { pub fn min_sum_square_diff(black_n1: Vec<i32>, black_n2: Vec<i32>, black_k1: i32, black_k2: i32) -> i64 { let mut black_diffs = vec![0i64; 100001]; for black_i in 0..black_n1.len() { black_diffs[(black_n1[black_i] - black_n2[black_i]).abs() as usize] += 1; } let mut black_k = black_k1 as i64 + black_k2 as i64; for black_d in (1..100001).rev() { if black_diffs[black_d] > 0 { let black_take = black_k.min(black_diffs[black_d]); black_diffs[black_d] -= black_take; black_diffs[black_d - 1] += black_take; black_k -= black_take; } } black_diffs.into_iter().enumerate().map(|(black_d, black_count)| black_count * (black_d as i64).pow(2)).sum() } }